import React from 'react';
import ReactDOM from 'react-dom/client';
import { BrowserRouter, Route, Routes } from 'react-router-dom'; // Import from 'react-router-dom' for version 6

import App from './App';
import CountryD from './CountryD/CountryD';

const router = (
  <Routes>
    <Route path={`${process.env}`} element={<App />} />
    <Route path={`${process.env}/country/:countryname`} element={<CountryD />} />
  </Routes>
);

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <BrowserRouter>{router}</BrowserRouter>
  </React.StrictMode>
);
